const bookVerbOrder = ['vivre', 'payer', 'choisir', 'voir', 'vouloir', "s'inscrire", 'savoir', 'connaître', 'dire', 'comprendre', 'attendre', 'pouvoir', 'courir', 'peindre', 'venir']

export function applyBookA2VerbOverrides(verbs: VerbEntry[]) {
  const orderMap = new Map(bookVerbOrder.map((infinitive, index) => [infinitive, index]))
  verbs.forEach((verb) => {
    const order = orderMap.get(verb.infinitive)
    if (order !== undefined) {
      verb.sequence = 50 + order
      verb.level = 'A2'
      verb.difficulty = 2
      verb.estimatedMinutes = 12
      verb.source = 'seed'
    }
  })
}
